SET NAMES utf8mb4;
UPDATE team_recommendations SET strengths='나현우 팀장 희망이 반영되어 일정 정리와 의사결정 중심 역할을 맡기 좋은 조합입니다. 윤지호의 Unity와 C#을 활용한 2D 협동 게임 구현 능력과 나현우의 Spring Security·Redis 기반 인증·인가 설계 경험이 만나 게임 네트워크와 백엔드 보안을 안정적으로 연결할 수 있습니다.', weaknesses='백엔드 구현 경험이 상대적으로 적어 API 설계와 데이터 저장 흐름이 한쪽에 몰릴 수 있습니다. 초반에는 인증·인가와 배치 처리 같은 핵심 백엔드 기능을 먼저 정리하고, 이후 Photon 네트워크와의 연동을 단계적으로 진행하는 방식이 필요합니다.' WHERE id=119;
UPDATE team_recommendations SET strengths='서강준 팀장 희망이 반영되어 일정 정리와 의사결정 중심 역할을 맡기 좋은 조합입니다. 노시현의 React·Node.js 기반 풀스택 개발 경험과 서강준의 Spring Boot·JPA 인증·데이터 구조 설계 능력이 만나 프론트엔드와 백엔드 간 API 명세를 일관되게 유지할 수 있습니다.', weaknesses='AI 구현 경험이 상대적으로 부족해 모델 학습·추론 파이프라인을 안정적으로 구축하기 어려울 수 있습니다. 초반에는 PyTorch·OpenCV 기반 이미지 분류 파이프라인을 단순화하고, 이후 FastAPI와 연동해 점진적으로 확장하는 방식이 필요합니다.' WHERE id=120;
UPDATE team_recommendations SET strengths='권서준 팀장 희망이 반영되어 일정 정리와 의사결정 중심 역할을 맡기 좋은 조합입니다. 홍다은의 SwiftUI·CoreData 기반 iOS 앱 구현 능력과 권서준의 Docker·GitHub Actions 기반 CI/CD 구축 경험이 만나 모바일 앱과 개발·배포 환경을 효율적으로 연결할 수 있습니다.', weaknesses='백엔드 구현 경험이 상대적으로 적어 API 설계와 데이터 저장 흐름이 한쪽에 몰릴 수 있습니다. 초반에는 Next.js·React 기반 프론트엔드 화면을 먼저 구현하고, 이후 LangChain·벡터 DB 기반 AI 기능을 단계적으로 연동하는 방식이 필요합니다.' WHERE id=121;
UPDATE team_recommendations SET strengths='배준호 팀장 희망이 반영되어 일정 정리와 의사결정 중심 역할을 맡기 좋은 조합입니다. 문태준의 Flutter·Firebase 기반 앱 구현 능력과 배준호의 Next.js·Spring Boot 기반 풀스택 개발 경험이 만나 모바일 앱과 웹 백엔드를 통합적으로 연결할 수 있습니다.', weaknesses='보안 구현 경험이 상대적으로 적어 JWT 인증 흐름과 OWASP 기준 취약점 점검이 미흡할 수 있습니다. 초반에는 이건우의 OWASP 기반 보안 점검 방안을 참고해 토큰 저장·만료·권한 체크 로직을 먼저 정리하고, 이후 전체 시스템에 적용하는 방식이 필요합니다.' WHERE id=122;
